<template>
<div class="social">
  <p class="greeting">
Feel free to reach out to me on the following platforms:
</p>
    <ul>
      <li v-for="entry in socialLinks" v-bind:key="entry.name">
        <a v-bind:href="entry.link">
          <eva-icon v-bind:name="entry.name" v-bind:height="50" v-bind:width="50" fill="gray"></eva-icon>
        </a>
      </li>
    </ul>

</div>
</template>

<script>
import data from '@/data'
export default {
  name: 'Social',
  data () {
    return {
      socialLinks: data.socialLinks
    }
  }
}
</script>
<style scoped>
.social li {
  display: inline-block;
  list-style-type: none;
  padding-right: 20px;
}

.greeting {
  padding-top: 20px;
  font-size: 1.5em;
  text-align: justify;
}

</style>



